 int peek() { if(stack.size() > 0) return stack.back(); return -1; } ;
 bool isEmpty() { return stack.empty(); } ;
} ;
int main() {
  Solution solution; int n;
  cin >> n; int x;
  for(int i = 0; i < n; i++) {
    cin >> x; solution.push(x);
  }
  cout << solution.peek() << endl;
